namespace ShipmentTracker.Client.Models;

public enum ShipmentStatus
{
    Created,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}

namespace ShipmentTracker.Client.Models;

public class ShipmentDto
{
    public Guid Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime LastUpdated { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string RecipientEmail { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Client.Models;

public class CreateShipmentRequest
{
    [Required, MaxLength(200)]
    public string Description { get; set; } = string.Empty;

    [Required, MaxLength(200)]
    public string Origin { get; set; } = string.Empty;

    [Required, MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    public DateTime? EstimatedDelivery { get; set; }

    [Required, MaxLength(100)]
    public string RecipientName { get; set; } = string.Empty;

    [Required, EmailAddress, MaxLength(200)]
    public string RecipientEmail { get; set; } = string.Empty;
}

using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetShipmentsAsync(ShipmentStatus? statusFilter = null, string? searchTerm = null);
    Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<ShipmentDto?> GetShipmentByIdAsync(Guid id);
    Task<bool> UpdateShipmentStatusAsync(Guid id, ShipmentStatus newStatus);
    Task<ShipmentDto> CreateShipmentAsync(CreateShipmentRequest request);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync(ShipmentStatus? statusFilter = null, string? searchTerm = null)
    {
        var query = new List<string>();
        if (statusFilter.HasValue)
            query.Add($"status={statusFilter.Value}");
        if (!string.IsNullOrWhiteSpace(searchTerm))
            query.Add($"search={Uri.EscapeDataString(searchTerm)}");

        var url = query.Count > 0 ? $"/api/shipments?{string.Join("&", query)}" : "/api/shipments";
        return await http.GetFromJsonAsync<List<ShipmentDto>>(url) ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(Guid id)
