using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public class Shipment
{
    public Guid Id { get; set; }

    [MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Description { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Origin { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    public int Status { get; set; }

    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime LastUpdated { get; set; }

    [MaxLength(100)]
    public string RecipientName { get; set; } = string.Empty;

    [MaxLength(200)]
    public string RecipientEmail { get; set; } = string.Empty;
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync(ShipmentStatus? statusFilter = null, string? searchTerm = null)
    {
        var query = db.Shipments.AsQueryable();

        if (statusFilter.HasValue)
            query = query.Where(s => s.Status == (int)statusFilter.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(s =>
                s.TrackingNumber.ToLower().Contains(term) ||
                s.Destination.ToLower().Contains(term) ||
                s.RecipientName.ToLower().Contains(term) ||
                s.Description.ToLower().Contains(term));
        }

        return await query
            .OrderByDescending(s => s.LastUpdated)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : ToDto(shipment);
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(Guid id)
    {
        var shipment = await db.Shipments.FindAsync(id);
        return shipment is null ? null : ToDto(shipment);
    }

    public async Task<bool> UpdateShipmentStatusAsync(Guid id, ShipmentStatus newStatus)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is null) return false;

        shipment.Status = (int)newStatus;
        shipment.LastUpdated = DateTime.UtcNow;
        await db.SaveChangesAsync();
        return true;
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentRequest request)
    {
        var shipment = new Shipment
        {
            Id = Guid.NewGuid(),
            TrackingNumber = GenerateTrackingNumber(),
            Description = request.Description,
            Origin = request.Origin,
            Destination = request.Destination,
            Status = (int)ShipmentStatus.Created,
            CreatedDate = DateTime.UtcNow,
            EstimatedDelivery = request.EstimatedDelivery,
            LastUpdated = DateTime.UtcNow,
            RecipientName = request.RecipientName,
            RecipientEmail = request.RecipientEmail
        };

        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Description = s.Description,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentStatus)s.Status,
        CreatedDate = s.CreatedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        LastUpdated = s.LastUpdated,
        RecipientName = s.RecipientName,
        RecipientEmail = s.RecipientEmail
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
    }
}

using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        group.MapGet("/", async (IShipmentService service, ShipmentStatus? status, string? search) =>
        {
            var shipments = await service.GetShipmentsAsync(status, search);
            return Results.Ok(shipments);
        });

        group.MapGet("/{id:guid}", async (IShipmentService service, Guid id) =>
        {
            var shipment = await service.GetShipmentByIdAsync(id);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Tracking endpoint is public — customers can look up by tracking number
        app.MapGet("/api/shipments/track/{trackingNumber}", async (IShipmentService service, string trackingNumber) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        group.MapPost("/", async (IShipmentService service, CreateShipmentRequest request) =>
        {
            var shipment = await service.CreateShipmentAsync(request);
            return Results.Created($"/api/shipments/{shipment.Id}", shipment);
        });

        group.MapPut("/{id:guid}/status", async (IShipmentService service, Guid id, StatusUpdateRequest request) =>
        {
            var success = await service.UpdateShipmentStatusAsync(id, request.Status);
            return success ? Results.NoContent() : Results.NotFound();
        });
    }
}

public record StatusUpdateRequest(ShipmentStatus Status);

