    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        group.MapGet("/", async (IShipmentService service, ShipmentStatus? status, string? search) =>
        {
            var shipments = await service.GetShipmentsAsync(status, search);
            return Results.Ok(shipments);
        });

        group.MapGet("/{id:guid}", async (IShipmentService service, Guid id) =>
        {
            var shipment = await service.GetShipmentByIdAsync(id);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Tracking endpoint is public — customers can look up by tracking number
        app.MapGet("/api/shipments/track/{trackingNumber}", async (IShipmentService service, string trackingNumber) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        group.MapPost("/", async (IShipmentService service, CreateShipmentRequest request) =>
        {
            var shipment = await service.CreateShipmentAsync(request);
            return Results.Created($"/api/shipments/{shipment.Id}", shipment);
        });

        group.MapPut("/{id:guid}/status", async (IShipmentService service, Guid id, StatusUpdateRequest request) =>
        {
            var success = await service.UpdateShipmentStatusAsync(id, request.Status);
            return success ? Results.NoContent() : Results.NotFound();
        });
    }
}

public record StatusUpdateRequest(ShipmentStatus Status);

