@page "/track/{TrackingNumber}"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services

<PageTitle>Track Shipment - @TrackingNumber</PageTitle>

<div class="container">
    <h2 class="mb-4">📍 Shipment Tracking</h2>

    @if (loading)
    {
        <div class="text-center my-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (shipment is null)
    {
        <div class="alert alert-warning">
            <h5>Shipment Not Found</h5>
            <p>No shipment found with tracking number <strong>@TrackingNumber</strong>.</p>
            <a href="/" class="btn btn-primary">Try Again</a>
        </div>
    }
    else
    {
        <div class="card shadow-sm mb-4">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">@shipment.TrackingNumber</h5>
                <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <dl>
                            <dt>Description</dt>
                            <dd>@shipment.Description</dd>
                            <dt>Origin</dt>
                            <dd>@shipment.Origin</dd>
                            <dt>Destination</dt>
                            <dd>@shipment.Destination</dd>
                        </dl>
                    </div>
                    <div class="col-md-6">
                        <dl>
                            <dt>Recipient</dt>
                            <dd>@shipment.RecipientName</dd>
                            <dt>Estimated Delivery</dt>
                            <dd>@(shipment.EstimatedDelivery?.ToString("MMMM dd, yyyy") ?? "Pending")</dd>
                            <dt>Last Updated</dt>
                            <dd>@shipment.LastUpdated.ToString("MMMM dd, yyyy h:mm tt") UTC</dd>
                        </dl>
                    </div>
                </div>

                <hr />
                <h6>Shipment Progress</h6>
                <div class="progress mb-3" style="height: 30px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @(GetProgressPercent(shipment.Status))%"
                         aria-valuenow="@GetProgressPercent(shipment.Status)"
                         aria-valuemin="0" aria-valuemax="100">
                        @shipment.Status
                    </div>
                </div>
                <div class="d-flex justify-content-between text-muted small">
                    <span>Created</span>
                    <span>Picked Up</span>
                    <span>In Transit</span>
                    <span>Out for Delivery</span>
                    <span>Delivered</span>
                </div>
            </div>
        </div>

        <div class="text-center">
            <button class="btn btn-outline-primary me-2" @onclick="Refresh">🔄 Refresh Status</button>
            <a href="/" class="btn btn-outline-secondary">← Track Another</a>
        </div>
    }
</div>

@code {
    [Parameter] public string TrackingNumber { get; set; } = string.Empty;
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private ShipmentDto? shipment;
    private bool loading = true;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipment();
    }

    private async Task LoadShipment()
    {
        loading = true;
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(TrackingNumber);
        loading = false;
    }

    private async Task Refresh() => await LoadShipment();

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Created => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Created => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        _ => 0
    };
}

@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Shipments Dashboard</PageTitle>

<div class="container">
    <div class="d-flex justify-content-between align-items-center mb-4">
        <h2>📋 Shipments Dashboard</h2>
        <a href="shipments/new" class="btn btn-success">➕ New Shipment</a>
    </div>

    <div class="row mb-3">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search by tracking #, destination, or recipient..."
                   @bind="searchTerm" @bind:event="oninput" @bind:after="LoadShipments" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="selectedStatus" @bind:after="LoadShipments">
                <option value="">All Statuses</option>
                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                {
                    <option value="@status">@status</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear</button>
        </div>
    </div>

    @if (loading)
    {
        <div class="text-center my-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (shipments.Count == 0)
    {
        <div class="alert alert-info">No shipments found matching your criteria.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Tracking #</th>
                        <th>Description</th>
                        <th>Destination</th>
                        <th>Recipient</th>
                        <th>Status</th>
                        <th>Est. Delivery</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var s in shipments)
                    {
                        <tr>
                            <td><a href="track/@s.TrackingNumber">@s.TrackingNumber</a></td>
                            <td>@s.Description</td>
                            <td>@s.Destination</td>
                            <td>@s.RecipientName</td>
                            <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                            <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                            <td>
                                @if (s.Status != ShipmentStatus.Delivered)
                                {
                                    <div class="dropdown">
                                        <button class="btn btn-sm btn-outline-primary dropdown-toggle" type="button"
                                                @onclick="() => ToggleDropdown(s.Id)" @onclick:stopPropagation="true">
                                            Update
                                        </button>
                                        @if (openDropdownId == s.Id)
                                        {
                                            <div class="dropdown-menu show">
                                                @foreach (var status in GetAvailableStatuses(s.Status))
                                                {
                                                    <button class="dropdown-item" @onclick="() => UpdateStatus(s.Id, status)">
                                                        @status
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                }
                                else
                                {
                                    <span class="text-success">✓ Complete</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <div class="text-muted">Showing @shipments.Count shipment(s)</div>
    }
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private List<ShipmentDto> shipments = [];
    private string searchTerm = string.Empty;
    private string selectedStatus = string.Empty;
    private bool loading = true;
    private Guid? openDropdownId;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        ShipmentStatus? statusFilter = Enum.TryParse<ShipmentStatus>(selectedStatus, out var s) ? s : null;
        shipments = await ShipmentService.GetShipmentsAsync(statusFilter, string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm);
        loading = false;
    }

    private async Task ClearFilters()
    {
        searchTerm = string.Empty;
        selectedStatus = string.Empty;
        await LoadShipments();
    }

    private void ToggleDropdown(Guid id)
    {
        openDropdownId = openDropdownId == id ? null : id;
    }

    private async Task UpdateStatus(Guid id, ShipmentStatus newStatus)
    {
        openDropdownId = null;
        await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
        await LoadShipments();
    }

    private static List<ShipmentStatus> GetAvailableStatuses(ShipmentStatus current) => current switch
    {
        ShipmentStatus.Created => [ShipmentStatus.PickedUp, ShipmentStatus.Delayed],
        ShipmentStatus.PickedUp => [ShipmentStatus.InTransit, ShipmentStatus.Delayed],
        ShipmentStatus.InTransit => [ShipmentStatus.OutForDelivery, ShipmentStatus.Delayed],
        ShipmentStatus.OutForDelivery => [ShipmentStatus.Delivered, ShipmentStatus.Delayed],
        ShipmentStatus.Delayed => [ShipmentStatus.InTransit, ShipmentStatus.OutForDelivery],
        _ => []
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Created => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

