@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Shipments Dashboard</PageTitle>

<div class="container">
    <div class="d-flex justify-content-between align-items-center mb-4">
        <h2>📋 Shipments Dashboard</h2>
        <a href="shipments/new" class="btn btn-success">➕ New Shipment</a>
    </div>

    <div class="row mb-3">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search by tracking #, destination, or recipient..."
                   @bind="searchTerm" @bind:event="oninput" @bind:after="LoadShipments" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="selectedStatus" @bind:after="LoadShipments">
                <option value="">All Statuses</option>
                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                {
                    <option value="@status">@status</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear</button>
        </div>
    </div>

    @if (loading)
    {
        <div class="text-center my-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (shipments.Count == 0)
    {
        <div class="alert alert-info">No shipments found matching your criteria.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Tracking #</th>
                        <th>Description</th>
                        <th>Destination</th>
                        <th>Recipient</th>
                        <th>Status</th>
                        <th>Est. Delivery</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var s in shipments)
                    {
                        <tr>
                            <td><a href="track/@s.TrackingNumber">@s.TrackingNumber</a></td>
                            <td>@s.Description</td>
                            <td>@s.Destination</td>
                            <td>@s.RecipientName</td>
                            <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                            <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                            <td>
                                @if (s.Status != ShipmentStatus.Delivered)
                                {
                                    <div class="dropdown">
                                        <button class="btn btn-sm btn-outline-primary dropdown-toggle" type="button"
                                                @onclick="() => ToggleDropdown(s.Id)" @onclick:stopPropagation="true">
                                            Update
                                        </button>
                                        @if (openDropdownId == s.Id)
                                        {
                                            <div class="dropdown-menu show">
                                                @foreach (var status in GetAvailableStatuses(s.Status))
                                                {
                                                    <button class="dropdown-item" @onclick="() => UpdateStatus(s.Id, status)">
                                                        @status
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                }
                                else
                                {
                                    <span class="text-success">✓ Complete</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <div class="text-muted">Showing @shipments.Count shipment(s)</div>
    }
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private List<ShipmentDto> shipments = [];
    private string searchTerm = string.Empty;
    private string selectedStatus = string.Empty;
    private bool loading = true;
    private Guid? openDropdownId;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        ShipmentStatus? statusFilter = Enum.TryParse<ShipmentStatus>(selectedStatus, out var s) ? s : null;
        shipments = await ShipmentService.GetShipmentsAsync(statusFilter, string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm);
        loading = false;
    }

    private async Task ClearFilters()
    {
        searchTerm = string.Empty;
        selectedStatus = string.Empty;
        await LoadShipments();
    }

    private void ToggleDropdown(Guid id)
    {
        openDropdownId = openDropdownId == id ? null : id;
    }

    private async Task UpdateStatus(Guid id, ShipmentStatus newStatus)
    {
        openDropdownId = null;
        await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
        await LoadShipments();
    }

    private static List<ShipmentStatus> GetAvailableStatuses(ShipmentStatus current) => current switch
    {
        ShipmentStatus.Created => [ShipmentStatus.PickedUp, ShipmentStatus.Delayed],
        ShipmentStatus.PickedUp => [ShipmentStatus.InTransit, ShipmentStatus.Delayed],
        ShipmentStatus.InTransit => [ShipmentStatus.OutForDelivery, ShipmentStatus.Delayed],
        ShipmentStatus.OutForDelivery => [ShipmentStatus.Delivered, ShipmentStatus.Delayed],
        ShipmentStatus.Delayed => [ShipmentStatus.InTransit, ShipmentStatus.OutForDelivery],
        _ => []
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Created => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

