@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Create Shipment</PageTitle>

<div class="container">
    <h2 class="mb-4">➕ Create New Shipment</h2>

    @if (createdShipment is not null)
    {
        <div class="alert alert-success">
            <h5>Shipment Created Successfully!</h5>
            <p>Tracking Number: <strong>@createdShipment.TrackingNumber</strong></p>
            <a href="track/@createdShipment.TrackingNumber" class="btn btn-primary me-2">View Shipment</a>
            <button class="btn btn-outline-secondary" @onclick="Reset">Create Another</button>
        </div>
    }
    else
    {
        <div class="card shadow-sm">
            <div class="card-body">
                <EditForm Model="request" OnValidSubmit="HandleSubmit" FormName="CreateShipment">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger" />

                    <div class="row">
                        <div class="col-md-6 mb-3">
                            <label for="description" class="form-label">Description</label>
                            <InputText id="description" class="form-control" @bind-Value="request.Description"
                                       placeholder="e.g. Electronics - Laptop" />
                            <ValidationMessage For="() => request.Description" />
                        </div>
                        <div class="col-md-6 mb-3">
                            <label for="estimatedDelivery" class="form-label">Estimated Delivery</label>
                            <InputDate id="estimatedDelivery" class="form-control" @bind-Value="request.EstimatedDelivery" />
                        </div>
                    </div>

                    <div class="row">
                        <div class="col-md-6 mb-3">
                            <label for="origin" class="form-label">Origin</label>
                            <InputText id="origin" class="form-control" @bind-Value="request.Origin"
                                       placeholder="e.g. Los Angeles, CA" />
                            <ValidationMessage For="() => request.Origin" />
                        </div>
                        <div class="col-md-6 mb-3">
                            <label for="destination" class="form-label">Destination</label>
                            <InputText id="destination" class="form-control" @bind-Value="request.Destination"
                                       placeholder="e.g. New York, NY" />
                            <ValidationMessage For="() => request.Destination" />
                        </div>
                    </div>

                    <div class="row">
                        <div class="col-md-6 mb-3">
                            <label for="recipientName" class="form-label">Recipient Name</label>
                            <InputText id="recipientName" class="form-control" @bind-Value="request.RecipientName"
                                       placeholder="e.g. Alice Johnson" />
                            <ValidationMessage For="() => request.RecipientName" />
                        </div>
                        <div class="col-md-6 mb-3">
                            <label for="recipientEmail" class="form-label">Recipient Email</label>
                            <InputText id="recipientEmail" class="form-control" @bind-Value="request.RecipientEmail"
                                       placeholder="e.g. alice@example.com" />
                            <ValidationMessage For="() => request.RecipientEmail" />
                        </div>
                    </div>

                    <div class="d-flex gap-2">
                        <button type="submit" class="btn btn-success" disabled="@submitting">
                            @if (submitting) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Create Shipment
                        </button>
                        <a href="shipments" class="btn btn-outline-secondary">Cancel</a>
                    </div>

                    @if (errorMessage is not null)
                    {
                        <div class="alert alert-danger mt-3">@errorMessage</div>
                    }
                </EditForm>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private CreateShipmentRequest request = new();
    private ShipmentDto? createdShipment;
    private bool submitting;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        submitting = true;
        errorMessage = null;
        try
        {
            createdShipment = await ShipmentService.CreateShipmentAsync(request);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create shipment: {ex.Message}";
        }
        finally
        {
            submitting = false;
        }
    }

    private void Reset()
    {
        request = new();
        createdShipment = null;
        errorMessage = null;
    }
}

